// Normalizes the Telegram trigger payload and checks for image files or documents
return $input.all().map(item => {
  const msg = item.json.message || item.json.edited_message || item.json.channel_post || {};
  const hasPhoto = !!(msg.photo || msg.document);
  return {
    json: {
      isScreenshot: hasPhoto,
      message: msg
    }
  };
});

// 1. Отримуємо всі вхідні елементи
const items = $input.all();

// 2. Об'єднуємо текст в один рядок
let rawText = items.map((item) => item.json.text).join(" ");

// 3. Очищаємо від знаків розмітки за допомогою регулярних виразів (Regex)
let cleanText = rawText
  .replace(/\*\*/g, "")       // Видаляет всі подвійні зірочки (жирный текст)
  .replace(/\*\/g, "")         // Видаляет поодинокі зірочки (курсив)
  .replace(/\\n/g, " ")       // Заменяет текстовые символы "\n" на обычные пробелы
  .replace(/\n/g, " ")        // Заменяет реальные переносы строк на пробелы
  .replace(/\s+/g, " ")       // Прибирает двойные или множественные пробелы, что образовались
  .trim();                    // Удаляет пробелы в начале и в конце текста

// 4. Повертаємо чистий результат в n8n
return [{ json: { text: cleanText } }];

